using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddSingleton<NotepadTools>();

builder.Services.AddChatClient(sp =>
{
    var openAiClient = new OpenAIClient(apiKey);
    return new OpenAIChatClient(openAiClient.GetChatClient(modelId));
});

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var notepadTools = host.Services.GetRequiredService<NotepadTools>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(notepadTools.AddNote),
    AIFunctionFactory.Create(notepadTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, you:
        1. Search the web for relevant information using the SearchWeb tool.
        2. Take notes on key findings using the AddNote tool.
        3. Perform additional searches to fill gaps or explore subtopics.
        4. Review your notes using GetNotes, then produce a clear summary.
        Be thorough — make at least 3 searches before summarizing.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");

    var prompt = $"Research the following topic and provide a comprehensive summary: {topic}";

    var response = await agent.RunAsync(prompt);

    Console.WriteLine(response.Text);

    Console.WriteLine("\n--- Notes collected ---");
    foreach (var note in notepadTools.Notes)
    {
        Console.WriteLine($"  • {note}");
    }

    notepadTools.Clear();
    Console.WriteLine();
}

// --- Tool classes ---

static class ResearchTools
{
    private static readonly HttpClient Http = new();

    [Description("Searches the web for information on a query and returns relevant results.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  [🔍 Searching: \"{query}\"]");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("AbstractText", out var abs)
                && abs.GetString() is { Length: > 0 } abstractText)
            {
                results.Add($"Summary: {abstractText}");
            }

            if (root.TryGetProperty("AbstractSource", out var src)
                && src.GetString() is { Length: > 0 } source)
            {
                results.Add($"Source: {source}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text)
                        && text.GetString() is { Length: > 0 } topicText)
                    {
                        results.Add($"- {topicText}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : "No results found. Try a different or more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }
}

